@startuml
title create order sequence diagram

actor Customer
participant "Cashier" as Cashier #90EEF5 
database ":Inventory System\n" as InventorySystem  { }  
entity :Order   { }   
control :Product    { }    
boundary :Stock     { }     
collections :Invoice      { }      
queue :Transaction        { }       

Customer ->> Cashier:1. Request order product \n2. Receive order 

activate Cashier  

group alt [IF (stock.qty > order.qty)]{
	Cashier->>+InventorySystem:3.requestCreateOrder()	
	InventorySystem->>+Product:3.1 selectProduct()\n3.4 return product

	group Product Stock Interaction {		
		 activate Product 		
		  Product->>+Stock:3.2 checkStock()		  
		   Stock-->-Product:3.3 return stock 		  		 	  	    	    		    		
		    deactivate Stock		    
		    	deactivate Product		    		    			    	



		        end group

	alt IF(stock.qty <order.qty) then else ELSE[ELSE]
	    loop for each item in cart do       
	        note right of OrderItem:\t\t\tsave to DB         
	    	endloop	    	      	      	     		      		     			      			     			    			   			  			 			 
	  endif	  	  	          

end group


@enduml
